    }
    .header {
      background-color: #b91c1c;
      padding: 24px 32px;
    }
    .header h1 {
      margin: 0;
      color: #ffffff;
      font-size: 18px;
      font-weight: 600;
      letter-spacing: 0.5px;
    }
    .header p {
      margin: 4px 0 0;
      color: #fecaca;
      font-size: 13px;
    }
    .body {
      padding: 28px 32px;
    }
    .intro {
      font-size: 14px;
      line-height: 1.6;
      color: #444444;
      margin: 0 0 24px;
    }
