      border-bottom: 1px solid #e8e8e8;
    }
    .details-table td {
      padding: 10px 16px;
      font-size: 13px;
    }
    .details-table td:first-child {
      color: #888888;
      width: 120px;
      font-weight: 500;
    }
    .details-table td:last-child {
      color: #222222;
      font-family: 'Courier New', Courier, monospace;
      font-size: 12px;
    }
    .analysis-box {
      background-color: #f9f9f9;
      border-left: 4px solid #b91c1c;
      border-radius: 0 6px 6px 0;
      padding: 16px 20px;
      margin-bottom: 24px;
      font-size: 13px;
      line-height: 1.7;
      color: #333333;
      white-space: pre-wrap;
    }
    .footer {
      border-top: 1px solid #e8e8e8;
      padding: 16px 32px;
      background-color: #fafafa;
      font-size: 12px;
      color: #999999;
      text-align: center;
    }
    .footer strong {
      color: #666666;
    }
